function getSourceSlice(
  source: string,
  startMarker: string,
  endMarker: string
) {
  const start = source.indexOf(startMarker);
  assert.notEqual(start, -1, `Missing source start marker: ${startMarker}`);
  const end = endMarker
    ? source.indexOf(endMarker, start + startMarker.length)
    : source.length;
  assert.notEqual(end, -1, `Missing source end marker: ${endMarker}`);

  return source.slice(start, end);
}

function summarizeAssignmentResultTableHeaders(
  headers: AssignmentResultTableHeaderView[]
) {
  return headers.map((header) => [header.id, header.label]);
}

function getAttemptAnswerValidationError(action: () => void) {
  let error: unknown;

  try {
    action();
  } catch (caught) {
    error = caught;
  }

  assert.ok(isAssignmentAttemptAnswerValidationError(error));
  return error;
}

function getTemplateRemixReadinessError(action: () => void) {
  let error: unknown;

  try {
    action();
  } catch (caught) {
    error = caught;
  }

  assert.ok(isTemplateRemixReadinessError(error));
  return error;
}

function findActivityDraftChecklistItem<
  T extends Pick<ActivityDraftReviewChecklistItem, 'id' | 'templateType'>,
>({
  id,
  items,
  templateType,
}: {
  id: ActivityDraftReviewChecklistItem['id'];
  items: readonly T[];
  templateType?: ActivityTemplateType;
}): T {
  const item = items.find(
    (candidate) =>
      candidate.id === id &&
      (templateType === undefined || candidate.templateType === templateType)
  );

  assert.ok(
    item,
    `Expected AI draft checklist item "${id}"${
      templateType ? ` for ${templateType}` : ''
    }.`
  );

  return item;
}

function findActivityDraftReviewGateMetric<
  T extends Pick<ActivityDraftMetaReviewGateMetricView, 'id'>,
>({
  id,
  metrics,
}: {
  id: ActivityDraftMetaReviewGateMetricView['id'];
  metrics: readonly T[];
}): T {
  const metric = metrics.find((candidate) => candidate.id === id);

  assert.ok(metric, `Expected AI draft review gate metric "${id}".`);

  return metric;
}

function findActivityDraftMetaHandoffItem<
  T extends Pick<ActivityDraftMetaHandoffItemView, 'id'>,
>({
  id,
  itemViews,
}: {
  id: ActivityDraftMetaHandoffItemId;
  itemViews: readonly T[];
}): T {
  const itemView = itemViews.find((candidate) => candidate.id === id);

  assert.ok(itemView, `Expected AI draft handoff item "${id}".`);

  return itemView;
}

function expectActivityDraftMetaHandoffPrivacy(
  view: ActivityDraftMetaHandoffView
) {
  const itemIds = view.itemViews.map((itemView) => itemView.id);

  assert.deepEqual(itemIds, [...ACTIVITY_DRAFT_META_HANDOFF_ITEM_IDS]);
  assert.equal(new Set(itemIds).size, 20);
  assert.deepEqual(view.privacy, {
    appliesToEditorBeforeSave: true,
    exposesAnswerText: false,
    exposesQuestionPromptText: false,
    exposesRawDraftJson: false,
    exposesRawSourceText: false,
    exposesSourceMaterialFileIds: false,
    exposesSourceMaterialStorageKeys: false,
    exposesTeacherNotesText: false,
    itemIds,
    publishesAssignmentWithoutTeacherAction: false,
    requiresTeacherReview: true,
    savesActivityWithoutTeacherAction: false,
    scope: 'teacher-reviewed-ai-draft',
  });
}

