const copiedTemplateMarkerPattern = new RegExp(
  [
    'getlangstudy',
    'Lang Study',
    'HSK',
    'Hanzi',
    'HSK1 starter loop',
    'TanStarter',
    'mkfast-template',
    'Chinese character',
    'stroke-order',
    'writing practice',
  ].join('|'),
  'i'
);

const sensitiveOauthPattern = new RegExp(
  [
    'GOCSPX-[A-Za-z0-9_-]+',
    '\\d{6,}-[a-z0-9_-]+\\.apps\\.googleusercontent\\.com',
    '客户端密钥',
  ].join('|'),
  'i'
);
const githubIssueTemplateConfigSource = readFileSync(
  '.github/ISSUE_TEMPLATE/config.yml',
  'utf8'
);
const viteConfigSource = readFileSync('vite.config.ts', 'utf8');
assert.match(
  githubIssueTemplateConfigSource,
  /ClassGamify Product Direction[\s\S]*docs\/product\.md[\s\S]*ClassGamify Classroom Feedback/,
  'GitHub issue template contact links should point contributors at ClassGamify product direction and classroom feedback.'
);
assert.doesNotMatch(
  githubIssueTemplateConfigSource,
  /TanStack Starter|tanstackstarter|mksaas\.link/,
  'GitHub issue template contact links should not point contributors back to copied starter-template resources.'
);
assert.doesNotMatch(
  viteConfigSource,
  /tanstarter\.dev|mksaas\.link/,
  'Vite dev server config should not keep copied starter-template hosts.'
);
assert.match(
  viteConfigSource,
  /allowedHosts:\s*\[\s*['"]\.trycloudflare\.com['"]\s*\]/,
  'Vite dev server config should only allow the current tunnel host needed for local ClassGamify previews.'
);
const secretScanFileExtensions = ['.json', '.md', '.ts', '.tsx', '.txt'];

function collectTextFiles(directoryPath: string): string[] {
  return readdirSync(directoryPath, { withFileTypes: true })
    .flatMap((entry) => {
      const filePath = `${directoryPath}/${entry.name}`;

      if (entry.isDirectory()) {
        return collectTextFiles(filePath);
      }

      return secretScanFileExtensions.some((extension) =>
        entry.name.endsWith(extension)
      )
        ? [filePath]
        : [];
    })
    .sort();
}

for (const filePath of [
  ...collectTextFiles('content'),
  ...collectTextFiles('docs'),
  ...collectTextFiles('project.inlang/messages'),
  ...collectTextFiles('scripts'),
  ...collectTextFiles('src'),
].filter((filePath) => filePath !== 'scripts/test-domain.ts')) {
  assert.doesNotMatch(
    readFileSync(filePath, 'utf8'),
    sensitiveOauthPattern,
    `${filePath} should not contain OAuth client secrets or concrete client ids.`
  );
}

