function buildExpectedStudentAttemptFeedbackScopeView({
  acceptedAlternativeItemCount,
  explanationItemCount,
  hiddenBySettings = false,
  needsReviewItemCount,
  reviewItemCount,
  unansweredItemCount,
}: {
  acceptedAlternativeItemCount: number;
  explanationItemCount: number;
  hiddenBySettings?: boolean;
  needsReviewItemCount: number;
  reviewItemCount: number;
  unansweredItemCount: number;
}) {
  const status = hiddenBySettings ? 'hidden' : 'visible';
  const statusLabel = hiddenBySettings ? 'Teacher review' : 'Visible';

  return {
    ariaLabel: 'Feedback coverage',
    description: hiddenBySettings
      ? 'Your teacher will review your answers. Correct answers, accepted alternatives, and explanations are hidden on this link.'
      : 'Your teacher allowed post-submit review. Item feedback below uses the same answer, alternatives, and explanation format across activity types.',
    hiddenBySettings,
    metricsLabel: 'Feedback coverage details',
    metrics: [
      {
        ariaLabel: hiddenBySettings
          ? 'Answer visibility: Hidden. Correct answers, accepted alternatives, and explanations stay teacher-only.'
          : 'Answer visibility: Shown. Correct answers, accepted alternatives, and explanations can appear below when available.',
        description: hiddenBySettings
          ? 'Correct answers, accepted alternatives, and explanations stay teacher-only.'
          : 'Correct answers, accepted alternatives, and explanations can appear below when available.',
        key: 'visibility',
        label: 'Answer visibility',
        value: hiddenBySettings ? 'Hidden' : 'Shown',
      },
      {
        ariaLabel: hiddenBySettings
          ? 'Item feedback: 0. No item feedback cards are shown while answers are hidden.'
          : `Item feedback: ${reviewItemCount}. Item feedback cards available below: ${reviewItemCount}.`,
        description: hiddenBySettings
          ? 'No item feedback cards are shown while answers are hidden.'
          : `Item feedback cards available below: ${reviewItemCount}.`,
        key: 'item-feedback',
        label: 'Item feedback',
        value: String(reviewItemCount),
      },
      {
        ariaLabel:
          `Alternatives: ${acceptedAlternativeItemCount}. ` +
          'Items with accepted alternatives beyond the primary answer.',
        description: 'Items with accepted alternatives beyond the primary answer.',
        key: 'accepted-alternatives',
        label: 'Alternatives',
        value: String(acceptedAlternativeItemCount),
      },
      {
        ariaLabel:
          `Explanations: ${explanationItemCount}. ` +
          'Items with teacher explanations.',
        description: 'Items with teacher explanations.',
        key: 'explanations',
        label: 'Explanations',
        value: String(explanationItemCount),
      },
      {
        ariaLabel:
          `Needs review: ${needsReviewItemCount}. ` +
          'Items that may need another look.',
        description: 'Items that may need another look.',
        key: 'needs-review',
        label: 'Needs review',
        value: String(needsReviewItemCount),
      },
      {
        ariaLabel:
          `Unanswered: ${unansweredItemCount}. Items left unanswered.`,
        description: 'Items left unanswered.',
        key: 'unanswered',
        label: 'Unanswered',
        value: String(unansweredItemCount),
      },
    ],
    status,
    statusAriaLabel: `Feedback visibility: ${statusLabel}`,
    statusLabel,
    title: 'Feedback coverage',
  };
}
function buildExpectedStudentRunnerSubmitReadinessView({
  answerCount,
  hasResult = false,
  isSubmitting = false,
  itemCount,
  readOnlyMessage,
  requiresIncompleteSubmitConfirmation = false,
  shareSlug,
  unansweredItemCount,
}: {
  answerCount: number;
  hasResult?: boolean;
  isSubmitting?: boolean;
  itemCount: number;
  readOnlyMessage?: string;
  requiresIncompleteSubmitConfirmation?: boolean;
  shareSlug: string;
  unansweredItemCount: number;
}) {
  const normalizedShareSlug = shareSlug.trim().toLowerCase();
  const shareStatus = normalizedShareSlug ? 'ready' : 'blocked';
  const itemStatus = itemCount > 0 ? 'ready' : 'blocked';
  const completionStatus =
    unansweredItemCount > 0 ? 'needs-action' : 'ready';
  const confirmationStatus =
    unansweredItemCount <= 0 || requiresIncompleteSubmitConfirmation
      ? 'ready'
      : 'needs-action';
  const submissionStatus = readOnlyMessage ? 'blocked' : 'ready';
  const items = [
    buildExpectedStudentRunnerSubmitReadinessItemView({
      description: normalizedShareSlug
        ? `This attempt will submit to the frozen link ${normalizedShareSlug}.`
        : 'This browser does not have a valid assignment share link for submission.',
      id: 'share-link',
      label: 'Assignment link',
      status: shareStatus,
    }),
    buildExpectedStudentRunnerSubmitReadinessItemView({
      description:
        itemCount > 0
          ? `${itemCount} runtime items loaded from the teacher assignment snapshot.`
          : 'No playable runtime items are available for this submission.',
      id: 'runtime-items',
      label: 'Frozen runtime items',
      status: itemStatus,
    }),
    buildExpectedStudentRunnerSubmitReadinessItemView({
      description:
        unansweredItemCount > 0
          ? `${unansweredItemCount} items still need answers or an intentional partial submit.`
          : `${answerCount} answered items are ready for submission.`,
      id: 'completion',
      label: 'Completion',
      status: completionStatus,
    }),
    buildExpectedStudentRunnerSubmitReadinessItemView({
      description: getExpectedStudentRunnerSubmitReadinessConfirmationDescription(
        {
          requiresIncompleteSubmitConfirmation,
          unansweredItemCount,
        }
      ),
      id: 'incomplete-confirmation',
      label: 'Partial-submit confirmation',
      status: confirmationStatus,
    }),
    buildExpectedStudentRunnerSubmitReadinessItemView({
      description: getExpectedStudentRunnerSubmitReadinessSubmissionDescription(
        {
          hasResult,
          isSubmitting,
          readOnlyMessage,
        }
      ),
      id: 'submission-state',
      label: 'Submission state',
      status: submissionStatus,
    }),
  ];
  const status = getExpectedStudentRunnerSubmitReadinessStatus(items);

  return {
    ariaLabel: 'Submit readiness checks',
    description:
      'Check the frozen link, loaded items, completion, and submit state before sending this attempt.',
    items,
    status,
    statusLabel: getExpectedStudentRunnerSubmitReadinessStatusLabel(status),
    title: 'Submit readiness',
  };
}

function buildExpectedStudentRunnerSubmitReadinessItemView({
  description,
  id,
  label,
  status,
}: {
  description: string;
  id: string;
  label: string;
  status: string;
}) {
  const statusLabel = getExpectedStudentRunnerSubmitReadinessStatusLabel(status);

  return {
    ariaLabel: `${label}: ${statusLabel}. ${description}`,
    description,
    id,
    label,
    status,
    statusLabel,
  };
}

function getExpectedStudentRunnerSubmitReadinessStatus(items: { status: string }[]) {
  if (items.some((item) => item.status === 'blocked')) return 'blocked';
  if (items.some((item) => item.status === 'needs-action')) {
    return 'needs-action';
  }

  return 'ready';
}

function getExpectedStudentRunnerSubmitReadinessStatusLabel(status: string) {
  if (status === 'blocked') return 'Unavailable';
  if (status === 'needs-action') return 'Needs review';

  return 'Ready';
}

function getExpectedStudentRunnerSubmitReadinessConfirmationDescription({
  requiresIncompleteSubmitConfirmation,
  unansweredItemCount,
}: {
  requiresIncompleteSubmitConfirmation: boolean;
  unansweredItemCount: number;
}) {
  if (unansweredItemCount <= 0) {
    return 'No second confirmation is needed because every item is answered.';
  }

  if (requiresIncompleteSubmitConfirmation) {
    return 'Your next submit action will confirm that unanswered items should stay blank.';
  }

  return 'Submit once to review unanswered items before sending a partial attempt.';
}

function getExpectedStudentRunnerSubmitReadinessSubmissionDescription({
  hasResult,
  isSubmitting,
  readOnlyMessage,
}: {
  hasResult: boolean;
  isSubmitting: boolean;
  readOnlyMessage?: string;
}) {
  if (readOnlyMessage) return readOnlyMessage;
  if (hasResult) return 'This attempt has already been submitted and saved.';
  if (isSubmitting) return 'The current attempt is already being saved.';

  return 'Submission is available for this loaded assignment.';
}
