function buildCsvWithAnalyzedAttemptDuration(
  durationSeconds: number | undefined
) {
  return buildAssignmentResultsCsv({
    ...csvExportData,
    analysis: {
      ...csvExportData.analysis,
      attempts: csvExportData.analysis.attempts.map((attempt, attemptIndex) =>
        attemptIndex === 0
          ? {
              ...attempt,
              durationSeconds,
            }
          : attempt
      ),
    },
  });
}
